import { supabase } from "./supabase";

/* --------- Tipos --------- */
export type Profile = {
  id: string;
  email: string | null;
  display_name: string | null;
  university: string | null;
  dob: string | null;
  photo_url: string | null;
};

export type Post = {
  id: string;
  author_id: string;
  content: string;
  likes_count: number;
  comments_count: number;
  created_at: string;
};

export type PostWithAuthor = Post & { author?: Profile; likedByMe?: boolean };

export type Comment = {
  id: string;
  post_id: string;
  user_id: string;
  content: string;
  created_at: string;
};
export type CommentWithAuthor = Comment & { author?: Profile };

/* --------- Helpers --------- */
async function getProfilesMap(ids: string[]): Promise<Map<string, Profile>> {
  if (!ids.length) return new Map();
  const { data, error } = await supabase
    .from("profiles")
    .select("id, email, display_name, university, dob, photo_url")
    .in("id", ids);
  if (error) throw error;
  const map = new Map<string, Profile>();
  (data ?? []).forEach((p: any) => map.set(p.id, p as Profile));
  return map;
}

/* --------- Universidades --------- */
export async function getUniversities(): Promise<string[]> {
  const { data, error } = await supabase
    .from("profiles")
    .select("university")
    .not("university", "is", null);
  if (error) throw error;
  const all = (data ?? [])
    .map((r: any) => (r.university || "").trim())
    .filter(Boolean);
  return Array.from(new Set(all)).sort((a, b) => a.localeCompare(b));
}

/* --------- Posts --------- */
export async function publishPost(authorId: string, content: string): Promise<Post> {
  const { data, error } = await supabase
    .from("posts")
    .insert({ author_id: authorId, content })
    .select("*")
    .single();
  if (error) throw error;
  return data as Post;
}

export async function getFeedForUser(userId: string, limit = 50): Promise<PostWithAuthor[]> {
  const { data: posts, error } = await supabase
    .from("posts")
    .select("*")
    .order("created_at", { ascending: false })
    .limit(limit);
  if (error) throw error;

  const p = posts ?? [];
  const authorIds = Array.from(new Set(p.map(x => x.author_id)));
  const authors = await getProfilesMap(authorIds);

  const postIds = p.map(x => x.id);
  const { data: likedRows } = await supabase
    .from("likes")
    .select("post_id")
    .eq("user_id", userId)
    .in("post_id", postIds);

  const likedSet = new Set((likedRows ?? []).map(r => r.post_id as string));
  return p.map(x => ({ ...x, author: authors.get(x.author_id), likedByMe: likedSet.has(x.id) }));
}

/** Feed filtrado por universidade */
export async function getFeedByUniversity(userId: string, university: string, limit = 50): Promise<PostWithAuthor[]> {
  const { data: authors, error: e1 } = await supabase
    .from("profiles")
    .select("id")
    .eq("university", university);
  if (e1) throw e1;

  const ids = (authors ?? []).map((r: any) => r.id);
  if (ids.length === 0) return [];

  const { data: posts, error: e2 } = await supabase
    .from("posts")
    .select("*")
    .in("author_id", ids)
    .order("created_at", { ascending: false })
    .limit(limit);
  if (e2) throw e2;

  const p = posts ?? [];
  const authorsMap = await getProfilesMap(ids);

  const postIds = p.map(x => x.id);
  const { data: likedRows } = await supabase
    .from("likes")
    .select("post_id")
    .eq("user_id", userId)
    .in("post_id", postIds);
  const likedSet = new Set((likedRows ?? []).map(r => r.post_id as string));

  return p.map(x => ({ ...x, author: authorsMap.get(x.author_id), likedByMe: likedSet.has(x.id) }));
}

export async function getMyPostsForUser(userId: string, limit = 50): Promise<PostWithAuthor[]> {
  const { data: posts, error } = await supabase
    .from("posts")
    .select("*")
    .eq("author_id", userId)
    .order("created_at", { ascending: false })
    .limit(limit);
  if (error) throw error;

  const p = posts ?? [];
  const authors = await getProfilesMap([userId]);

  const postIds = p.map(x => x.id);
  const { data: likedRows } = await supabase
    .from("likes")
    .select("post_id")
    .eq("user_id", userId)
    .in("post_id", postIds);
  const likedSet = new Set((likedRows ?? []).map(r => r.post_id as string));

  return p.map(x => ({ ...x, author: authors.get(userId), likedByMe: likedSet.has(x.id) }));
}

export async function getMyProfile(userId: string): Promise<Profile | null> {
  const { data, error } = await supabase
    .from("profiles")
    .select("*")
    .eq("id", userId)
    .maybeSingle();
  if (error) throw error;
  return (data ?? null) as Profile | null;
}

/* --------- Likes --------- */
export async function toggleLike(postId: string, userId: string): Promise<boolean> {
  const { data: exists } = await supabase
    .from("likes")
    .select("post_id")
    .eq("post_id", postId)
    .eq("user_id", userId)
    .maybeSingle();

  if (exists) {
    const { error } = await supabase
      .from("likes")
      .delete()
      .eq("post_id", postId)
      .eq("user_id", userId);
    if (error) throw error;
    return false;
  } else {
    const { error } = await supabase
      .from("likes")
      .insert({ post_id: postId, user_id: userId });
    if (error) throw error;
    return true;
  }
}

/* --------- Comentários --------- */
export async function addComment(postId: string, userId: string, content: string): Promise<Comment> {
  const { data, error } = await supabase
    .from("comments")
    .insert({ post_id: postId, user_id: userId, content })
    .select("*")
    .single();
  if (error) throw error;
  return data as Comment;
}

export async function getCommentsWithAuthors(postId: string): Promise<CommentWithAuthor[]> {
  const { data, error } = await supabase
    .from("comments")
    .select("*")
    .eq("post_id", postId)
    .order("created_at", { ascending: true });
  if (error) throw error;

  const list = (data ?? []) as Comment[];
  const ids = Array.from(new Set(list.map(c => c.user_id)));
  const authors = await getProfilesMap(ids);
  return list.map(c => ({ ...c, author: authors.get(c.user_id) }));
}

/** Apenas o autor pode apagar (checamos pelo where user_id = ...) */
export async function deleteComment(commentId: string, userId: string): Promise<void> {
  const { error } = await supabase
    .from("comments")
    .delete()
    .eq("id", commentId)
    .eq("user_id", userId);
  if (error) throw error;
}

/* --------- Realtime (opcional) --------- */
export function subscribeNewPosts(cb: (post: Post) => void) {
  const ch = supabase
    .channel("posts-feed")
    .on("postgres_changes",
      { event: "INSERT", schema: "public", table: "posts" },
      (payload: any) => cb(payload.new as Post)
    )
    .subscribe();
  return () => { supabase.removeChannel(ch); };
}
