import React from "react";
import "./SignIn.css";

// importa imagens direto do src
import googleIcon from "../assets/google-icon.png";
import appleIcon from "../assets/apple-icon.png";
import illustration from "../assets/login-illustration.png";

interface SignInProps {
  onGoogle: () => void;
  onApple: () => void;
}

const SignIn: React.FC<SignInProps> = ({ onGoogle, onApple }) => {
  return (
    <div className="signin-container">
      <div className="signin-card">
        {/* Imagem da esquerda */}
        <div className="signin-left">
          <img src={illustration} alt="Universidade internacional" />
          <h3>Universidade internacional</h3>
        </div>

        {/* Conteúdo principal */}
        <div className="signin-right">
          <h1 className="signin-title">Bem-vindo 🎓</h1>
          <p className="signin-subtitle">
            Conecte-se com colegas do mundo todo
          </p>

          {/* Botões de login */}
          <button className="btn-google" onClick={onGoogle}>
            <img src={googleIcon} alt="Google" />
            Entrar com Google
          </button>

          <button className="btn-apple" onClick={onApple}>
            <img src={appleIcon} alt="Apple" />
            Entrar com Apple
          </button>
        </div>
      </div>
    </div>
  );
};

export default SignIn;
