import React, { useState } from "react";
import { supabase } from "../supabase";
import "./OnboardingWizard.css";

type Props = { onDone: () => void };

export default function OnboardingWizard({ onDone }: Props) {
  const [step, setStep] = useState(0);
  const [university, setUniversity] = useState("");
  const [dob, setDob] = useState("");

  const totalSteps = 3;

  const next = async () => {
    if (step === totalSteps - 1) {
      const user = (await supabase.auth.getUser()).data.user;
      if (user) {
        await supabase.from("profiles").upsert({
          id: user.id,
          university,
          dob,
        });
      }
      onDone();
    } else {
      setStep(step + 1);
    }
  };

  return (
    <div className="owz-container">
      <h2>Bem-vindo 🎓</h2>

      <div className="owz-steps">
        {Array.from({ length: totalSteps }).map((_, i) => (
          <React.Fragment key={i}>
            <div
              className={`owz-step ${
                i === step ? "is-active" : i < step ? "is-done" : ""
              }`}
            >
              <div className="owz-step-dot">{i + 1}</div>
            </div>
            {i < totalSteps - 1 && (
              <div
                className={`owz-step-line ${
                  i < step ? "is-filled" : ""
                }`}
              ></div>
            )}
          </React.Fragment>
        ))}
      </div>

      {step === 0 && (
        <div>
          <label>Universidade</label>
          <input
            value={university}
            onChange={(e) => setUniversity(e.target.value)}
            placeholder="Digite sua universidade"
          />
        </div>
      )}

      {step === 1 && (
        <div>
          <label>Data de nascimento</label>
          <input
            type="date"
            value={dob}
            onChange={(e) => setDob(e.target.value)}
          />
        </div>
      )}

      {step === 2 && (
        <div>
          <p>Revise suas informações e clique em concluir ✅</p>
          <ul>
            <li><b>Universidade:</b> {university}</li>
            <li><b>Nascimento:</b> {dob}</li>
          </ul>
        </div>
      )}

      <button className="btn primary" onClick={next}>
        {step === totalSteps - 1 ? "Concluir" : "Próximo"}
      </button>
    </div>
  );
}
