import React, { useEffect, useState } from "react";
import {
  GoogleAuthProvider,
  onAuthStateChanged,
  signInWithPopup,
  signOut,
  User,
} from "firebase/auth";
import { auth } from "./firebase";
import { supabase } from "./supabase";

import SignIn from "./pages/SignIn";
import Feed from "./pages/Feed";
import Notifications from "./pages/Notifications";
import Chat from "./pages/Chat";
import ProfilePage from "./pages/Profile";
import OnboardingWizard from "./components/OnboardingWizard";
import Logo from "./components/Logo";

import "./App.css";

type Tab = "feed" | "chat" | "notifications" | "profile";

export default function App() {
  const [user, setUser] = useState<User | null>(null);
  const [tab, setTab] = useState<Tab>("feed");
  const [loading, setLoading] = useState(true);
  const [needsOnboarding, setNeedsOnboarding] = useState(false);

  useEffect(() => {
    const unsub = onAuthStateChanged(auth, async (u) => {
      setUser(u);
      if (!u) {
        setLoading(false);
        return;
      }

      const { data, error } = await supabase
        .from("profiles")
        .select("university, dob")
        .eq("id", u.uid)
        .maybeSingle();

      if (error) {
        console.error(error);
      }

      setNeedsOnboarding(!data || !data.university || !data.dob);
      setLoading(false);
    });
    return () => unsub();
  }, []);

  if (loading) return <div className="center">Carregando…</div>;

  if (!user) {
    return (
      <SignIn
        onGoogle={async () => signInWithPopup(auth, new GoogleAuthProvider())}
        onApple={() => alert("Login com Apple virá depois.")}
      />
    );
  }

  if (needsOnboarding) {
    return <OnboardingWizard onDone={() => setNeedsOnboarding(false)} />;
  }

  return (
    <div className="shell">
      <header className="topbar">
        <div style={{ display: "flex", alignItems: "center", gap: 8 }}>
          <Logo />
        </div>
        <div className="topbar-right">
          <span className="topbar-name">{user.displayName ?? user.email}</span>
          <button className="btn ghost" onClick={() => signOut(auth)}>
            Sair
          </button>
        </div>
      </header>

      <main className="page">
        {tab === "feed" && <Feed />}
        {tab === "notifications" && <Notifications />}
        {tab === "chat" && <Chat />}
        {tab === "profile" && <ProfilePage />}
      </main>

      <nav className="tabbar">
        <button
          className={tab === "feed" ? "tab active" : "tab"}
          onClick={() => setTab("feed")}
          title="Feed"
        >
          🏠
        </button>
        <button
          className={tab === "chat" ? "tab active" : "tab"}
          onClick={() => setTab("chat")}
          title="Mensagens"
        >
          ✉️
        </button>
        <button
          className={tab === "notifications" ? "tab active" : "tab"}
          onClick={() => setTab("notifications")}
          title="Notificações"
        >
          🔔 <span className="badge">5</span>
        </button>
        <button
          className={tab === "profile" ? "tab active" : "tab"}
          onClick={() => setTab("profile")}
          title="Perfil"
        >
          👤
        </button>
      </nav>
    </div>
  );
}
