import React, { useEffect, useState } from "react";
import { auth } from "../firebase";
import { getMyPostsForUser, getMyProfile, PostWithAuthor, Profile } from "../api";
import PostItem from "../components/PostItem";

function slugify(s: string) {
  return s.toLowerCase().normalize("NFD").replace(/[\u0300-\u036f]/g, "")
    .replace(/[^a-z0-9]+/g, "").slice(0, 18) || "universidade";
}

export default function ProfilePage() {
  const u = auth.currentUser!;
  const [profile, setProfile] = useState<Profile | null>(null);
  const [posts, setPosts] = useState<PostWithAuthor[]>([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    (async () => {
      const [p, ps] = await Promise.all([
        getMyProfile(u.uid),
        getMyPostsForUser(u.uid, 50),
      ]);
      setProfile(p);
      setPosts(ps);
      setLoading(false);
    })();
  }, [u.uid]);

  if (loading) return <div className="card">Carregando…</div>;

  const uni = profile?.university || "";
  const handle = uni ? `@${slugify(uni)}` : "";

  return (
    <div>
      {/* header simples, sem capa */}
      <div className="card" style={{ display: "flex", gap: 16, alignItems: "center" }}>
        <img
          className="avatar"
          src={profile?.photo_url || `https://i.pravatar.cc/120?u=${u.uid}`}
          alt=""
          style={{ width: 96, height: 96, borderRadius: 999 }}
        />
        <div style={{ lineHeight: 1.3 }}>
          <div style={{ fontSize: 22, fontWeight: 700 }}>
            {profile?.display_name || u.displayName || u.email}
          </div>
          {handle && <div className="muted" style={{ marginTop: 2 }}>{handle}</div>}
          <div className="muted" style={{ marginTop: 6 }}>
            {uni}
          </div>
          {profile?.dob && (
            <div className="muted">Nascido(a) em {new Date(profile.dob).toLocaleDateString()}</div>
          )}
        </div>
      </div>

      <h3 className="title" style={{ marginTop: 14 }}>Posts</h3>

      <div className="feed">
        {posts.map((p) => <PostItem key={p.id} post={p} />)}
        {posts.length === 0 && <div className="card">Sem publicações ainda.</div>}
      </div>
    </div>
  );
}
